export const COMPANY_QUESTIONS: Record<string, Question[]> = {
  google: [
    { id:'cg1', topic:'Google', sub:'System Design', diff:'H', type:'design', q:'Design Google Search — inverted index, query processing, ranking at web scale.', cos:['google'], points:['Crawl: Googlebot discovers pages via links. Distributed crawl queue, robots.txt respect, rate limiting','Index: inverted index maps term → (docId, position, frequency) list. Stored in Bigtable/Colossus','Ranking: multi-signal (BM25 relevance, PageRank link authority, freshness, user signals, ML BERT reranking)','Serving: query → rewrite/expand → retrieve candidates (L0 fast filter → L1 → L2 rerank → blend ads)','Infrastructure: 70+ data centers, Borg orchestration, Spanner for consistent metadata, GFS for docs'] },
    { id:'cg2', topic:'Google', sub:'System Design', diff:'H', type:'design', q:'Design YouTube video upload, processing pipeline, and adaptive streaming.', cos:['google'], points:['Upload: resumable chunked upload to GCS. Client uploads 256KB chunks with retry on failure','Processing: Cloud Tasks queue → transcoding workers (multiple resolutions: 144p→4K, multiple codecs: H.264, VP9, AV1)','Storage: hot videos on CDN edge, warm on regional, cold on Colossus (object store). Cost tiering.','Streaming: DASH/HLS manifests. Adaptive bitrate: player switches based on bandwidth. Segment duration 2-10s','Thumbnails: ML selects best frames. Captions: automatic speech recognition + upload support'] },
  ],
  meta: [
    { id:'cm1', topic:'Meta', sub:'System Design', diff:'H', type:'design', q:'Design Facebook News Feed at 3 billion users scale.', cos:['meta'], points:['Candidate generation: posts from friends/followed pages (TAO graph DB query), ads, suggested content','Ranking: two-stage. L1: fast feature-based scoring. L2: ML model (engagement probability, diversity)','Features: affinity score, content type, time decay, user history, A/B test group assignments','Serving: for most users: precomputed feed in Redis (fan-out on write). Celebrities: computed on read (fan-out on read)','Infrastructure: TAO for social graph, Scuba for real-time analytics, Memcache for hot data'] },
    { id:'cm2', topic:'Meta', sub:'Coding', diff:'H', type:'coding', q:'Design and implement a thread-safe LRU Cache with expiry support.', cos:['meta'], points:['LRU core: HashMap<K, DLLNode> + Doubly Linked List. O(1) get/put. Add to head, remove from tail.','Thread safety: ReentrantReadWriteLock. Read lock for get, write lock for put/evict. Or synchronized methods','Expiry: store expiry timestamp in node. Background thread sweeps expired entries periodically','Or lazy expiry: check on get/put if entry expired, remove then. Simpler but stale entries linger until accessed'] },
  ],
  amazon: [
    { id:'ca1', topic:'Amazon', sub:'Leadership', diff:'M', type:'behavioral', q:'Amazon Leadership Principle: Customer Obsession — working backwards from customer. Real example.', cos:['amazon'], points:['Write the press release first (PR/FAQ working backwards method), then decide what to build','Customer interviews: talk to 5+ customers before writing code. Understand job-to-be-done not just feature request','Show: you changed your technical approach based on customer feedback, not just requirements doc','Quantify customer impact: "reduced checkout errors by 30%, saving customers X minutes per transaction"'] },
    { id:'ca2', topic:'Amazon', sub:'System Design', diff:'H', type:'design', q:'Design Amazon Product Detail Page — 200M products, 1B+ page views/day.', cos:['amazon'], points:['Components: product service, inventory service, price service, review service, recommendation service','Caching: Varnish/CloudFront for entire page (TTL 5min). Per-component cache for dynamic sections (price: 30s, inventory: 5s)','Personalization: user-specific sections (recommendations, "viewed with") computed separately, inject client-side','Availability: each component independent. Product info unavailable → show from cache. Reviews unavailable → hide section','CDN: S3 for images/assets with CloudFront. A+ content in S3. Price + availability via dynamic API calls'] },
  ],
  microsoft: [
    { id:'cmi1', topic:'Microsoft', sub:'System Design', diff:'H', type:'design', q:'Design Microsoft Teams real-time collaboration (messages, presence, video calls).', cos:['microsoft'], points:['Messages: SignalR/WebSocket for real-time delivery. Kafka for durable message bus. CosmosDB for storage','Presence: heartbeat every 30s. Redis pub/sub to fan out status changes to subscribed clients','Video calls: WebRTC for peer-to-peer (≤ few people). SFU (Selective Forwarding Unit) for large calls > 4 people','Scalability: rooms partitioned across servers. Presence partitioned by user ID hash','Reliability: message delivery with ACK + retry. Store-and-forward for offline users. Push notifications'] },
  ],
  flipkart: [
    { id:'cf1', topic:'Flipkart', sub:'System Design', diff:'H', type:'design', q:'Design a Flash Sale system for Big Billion Days — 100K orders/second spike.', cos:['flipkart'], points:['Pre-sale: warm up inventory cache (Redis). Pre-create user tokens. Queue position assignment','Rate limiting: token bucket per user. Queue system (SQS FIFO) for order processing. Virtual queue UI','Inventory: optimistic locking in DB. Redis counter with DECR (atomic). Lua script for atomic check-decrement','Oversell prevention: reserve in Redis, confirm in DB asynchronously. Compensation if DB fails','Scaling: stateless app servers (scale out), Redis cluster, read replicas for product catalog (no flash sale writes)'] },
  ],
  atlassian: [
    { id:'cat1', topic:'Atlassian', sub:'System Design', diff:'H', type:'design', q:'Design Jira — issue tracking for enterprise with complex permissions, search, workflows.', cos:['atlassian'], points:['Permission model: hierarchical (Organization > Site > Project > Issue). Roles and ACLs. Evaluated at query time','Workflow: state machine per issue type. Transitions with conditions (required fields), validators, post-functions','Search: JQL (Jira Query Language) → parsed to Elasticsearch query. Indexed: summary, description, assignee, status, custom fields','Real-time: WebSocket for issue updates. Redis pub/sub for collaboration (who\'s viewing this issue)','Scale: tenant isolation (each Jira instance = tenant). Multi-tenant DB with tenant_id in every table. Separate Elasticsearch per large tenant'] },
  ],
};

